  ('retired-d0d1b9a2-moex-00300', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-3d2b73b6', 'sub-retired-d0d1b9a2-05', NULL, 'single_choice', '依憲法法庭111年憲判字第6號判決，地方自治條例中有關「萊劑零檢岀」規定，「逾越地方自治立法權 的範圍及界限」的理由，並不包含下列何者？', '["中央法律保留", "中央法律優位", "規範效果明顯干預各該轄區外居民之權利義務", "憲法無明文規定保障直轄市自治事項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00301', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-3d2b73b6', 'sub-retired-d0d1b9a2-05', NULL, 'single_choice', '下列與平等權有關之案件中，何者未經大法官認定差別待遇之目的與手段間不具「實質關聯」？', '["以主觀上有無意圖得利，作為是否處罰「與人姦宿」之差別待遇標準", "就受長期照護者之醫藥費，以付與特定醫療院所者為限，始得列舉扣除之規定", "扶養其他親屬或家屬須未滿20歲或年滿60歲，始得減除免稅額之規定", "僅限制「跨國」婚姻媒合，不得要求或期約報酬"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00302', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-3d2b73b6', 'sub-retired-d0d1b9a2-05', NULL, 'single_choice', '甲、乙及丙三人分別出資新臺幣100萬元、200萬元及300萬元，成立一間有限公司。有關三人於該公司 間之法律關係，下列敘述何者錯誤？', '["未來如公司欲增資，任何同意增資之股東，仍無按原出資數比例出資之義務", "甲、乙及丙對於公司之責任，除其三人特別約定外，以其出資額為限", "如章程未訂定按出資多寡比例分配表決權，甲、乙及丙三人均有一表決權", "公司應在本公司備置股東名簿，記載各股東出資額"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00303', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-3d2b73b6', 'sub-retired-d0d1b9a2-05', NULL, 'single_choice', '依勞動基準法之規定，雇主與勞工間最低服務年限之約定，不得逾越合理範圍。下列何者非屬該合理範圍 之應考量事項？', '["從事相同或類似職務之勞工，其人力替補可能性", "雇主提供勞工補償之額度及範圍", "雇主為勞工進行專業技術培訓之期間及成本", "勞工擔任之職位或職務，能接觸或使用雇主之營業秘密"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00304', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-3d2b73b6', 'sub-retired-d0d1b9a2-05', NULL, 'single_choice', '依行政程序法規定，行政機關應依職權調查證據。下列敘述何者錯誤？', '["對於當事人有利、不利之事項，一律注意", "當事人於行政程序中，得自行提出證據", "行政機關調查證據，應受當事人主張之拘束", "機關在為決定時，即應斟酌全部陳述與調查事實及證據的結果 2701"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00305', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-112-3d2b73b6', 'sub-retired-d0d1b9a2-05', NULL, 'single_choice', '關於法律之廢止，下列敘述何者正確？', '["法律之廢止，直接由總統依職權公布即可生效", "法律之廢止應將擬廢止之法律全文刊載，不得僅公布法律名稱與施行日期", "法律定有施行期限者，期滿當然廢止，主管機關不必公告", "法律定有施行期限者，主管機關認為需要延長者，應於期限屆滿一個月前送立法院審議"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:12+00:00", "source_pdf_sha1": "87de1eee000f", "answer_pdf_sha1": "3e2ca2064eed", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "136", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、法學緒論、英文)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
